### Extend Drizzle Schema with Custom Columns and Indexes using Payload `afterSchemaInit` Hook

Source: https://github.com/payloadcms/payload/blob/main/docs/database/sqlite.mdx

This snippet demonstrates how to use the `afterSchemaInit` hook with `sqliteAdapter` in Payload CMS to extend a Drizzle schema. It adds an `extra_integer_column` and a composite index (`country_city_composite_index`) to the 'places' collection table. It leverages the `extendTable` utility provided by Payload to modify the schema after it has been built.

```ts
import { sqliteAdapter } from '@payloadcms/db-sqlite'
import { index, integer } from '@payloadcms/db-sqlite/drizzle/sqlite-core'
import { buildConfig } from 'payload'

export default buildConfig({
  collections: [
    {
      slug: 'places',
      fields: [
        {
          name: 'country',
          type: 'text',
        },
        {
          name: 'city',
          type: 'text',
        },
      ],
    },
  ],
  db: sqliteAdapter({
    afterSchemaInit: [
      ({ schema, extendTable, adapter }) => {
        extendTable({
          table: schema.tables.places,
          columns: {
            extraIntegerColumn: integer('extra_integer_column'),
          },
          extraConfig: (table) => ({
            country_city_composite_index: index(
              'country_city_composite_index',
            ).on(table.country, table.city),
          }),
        })

        return schema
      },
    ],
  }),
})
```

